-- ============================================================
-- Smart Energy Analytics Platform — Sample Seed Data
-- MySQL 8.0+ compatible
--
-- Run this AFTER schema.sql has been executed.
--
-- IMPORTANT — PASSWORDS:
-- The `password` column below contains PLACEHOLDER bcrypt
-- hashes (60-character strings starting with $2b$12$...) that
-- are NOT cryptographically valid for the documented
-- passwords, because this hash must be generated by
-- Flask-Bcrypt using your app's secret/runtime — it cannot be
-- hand-written in SQL.
--
-- After running this file, set REAL passwords by running:
--
--     flask shell
--     >>> from src.models.user import User
--     >>> from app import db
--     >>> admin = User.query.filter_by(username="admin").first()
--     >>> admin.set_password("Admin@123")
--     >>> demo  = User.query.filter_by(username="demo_user").first()
--     >>> demo.set_password("User@123")
--     >>> db.session.commit()
--
-- (A ready-to-run script `database/set_sample_passwords.py`
--  automates exactly this — see the implementation notes.)
-- ============================================================

SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

-- ============================================================
-- 1. USERS — 1 admin + 1 normal user
-- ============================================================
     `role`, `is_active`, `last_login`, `created_at`)
VALUES
    (1, 'admin', 'admin@smartenergy.com',
     '$2b$12$PLACEHOLDERHASHADMIN00000000000000000000000000000000',
     'System', 'Administrator', 'admin', 1, NOW(), NOW() - INTERVAL 120 DAY),

    (2, 'demo_user', 'demo@smartenergy.com',
     '$2b$12$PLACEHOLDERHASHDEMOUSER0000000000000000000000000000000',
